@namespace Lumeo

<div class="@ContainerClass"
     role="img"
     aria-label="@($"Barcode: {Value}")"
     @attributes="AdditionalAttributes">
    @if (!string.IsNullOrEmpty(Value))
    {
        <svg width="@SvgWidth" height="@SvgHeight"
             viewBox="0 0 @SvgWidth @SvgHeight"
             xmlns="http://www.w3.org/2000/svg"
             style="display:block;">
            @* Background *@
            <rect x="0" y="0" width="@SvgWidth" height="@SvgHeight"
                  fill="var(--color-@BackgroundColor, var(--color-background))" />
            @* Bars *@
            @{
                double xPos = QuietZone;
                foreach (var (width, isBar) in _modules)
                {
                    if (isBar)
                    {
                        <rect x="@xPos.ToString(System.Globalization.CultureInfo.InvariantCulture)"
                              y="0"
                              width="@width.ToString(System.Globalization.CultureInfo.InvariantCulture)"
                              height="@Height"
                              fill="var(--color-@Color, var(--color-foreground))" />
                    }
                    xPos += width;
                }
            }
            @* Text below bars rendered via foreignObject so we avoid Razor <text> conflict *@
            @if (ShowText)
            {
                <foreignObject x="0" y="@Height" width="@SvgWidth" height="20">
                    <div xmlns="http://www.w3.org/1999/xhtml"
                         style="@($"width:{SvgWidth}px;text-align:center;font-size:11px;font-family:monospace;color:var(--color-{Color});line-height:18px;")">
                        @Value
                    </div>
                </foreignObject>
            }
        </svg>
    }
</div>

@code {
    [Parameter] public string Value { get; set; } = "";
    [Parameter] public BarcodeFormat Format { get; set; } = BarcodeFormat.Code128;
    [Parameter] public int Height { get; set; } = 80;
    [Parameter] public double BarWidth { get; set; } = 2;
    [Parameter] public bool ShowText { get; set; } = true;
    [Parameter] public string Color { get; set; } = "foreground";
    [Parameter] public string BackgroundColor { get; set; } = "background";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private const int QuietZone = 10;

    private List<(double Width, bool IsBar)> _modules = new();

    private int SvgWidth => (int)Math.Ceiling(_modules.Sum(m => m.Width) + QuietZone * 2);
    private int SvgHeight => ShowText ? Height + 20 : Height;

    private string ContainerClass => $"inline-block {Class}".Trim();

    protected override void OnParametersSet() => Rebuild();

    private void Rebuild()
    {
        _modules.Clear();
        if (string.IsNullOrEmpty(Value)) return;
        try
        {
            var bits = Code128B.Encode(Value);
            foreach (var bit in bits)
                _modules.Add((BarWidth, bit));
        }
        catch
        {
            _modules.Clear();
        }
    }

    public enum BarcodeFormat { Code128, Code39, EAN13 }

    // ─── Code 128B encoder ───────────────────────────────────────────────────
    // Code Set B covers ASCII 32–127. Each symbol is an 11-module pattern of
    // 3 bars and 3 spaces. The stop symbol is 13 modules (4 bars, 3 spaces + guard).
    // Reference: https://en.wikipedia.org/wiki/Code_128
    private static class Code128B
    {
        // 107 symbols (values 0–106) encoded as 11 bits (1=bar, 0=space).
        // Start Code B = symbol 104, Stop = special 13-module pattern.
        // Each entry is a string of 11 '0'/'1' chars: bar=1, space=0.
        private static readonly string[] Patterns =
        {
            "11011001100", // 0  — SP
            "11001101100", // 1  — !
            "11001100110", // 2  — "
            "10010011000", // 3  — #
            "10010001100", // 4  — $
            "10001001100", // 5  — %
            "10011001000", // 6  — &
            "10011000100", // 7  — '
            "10001100100", // 8  — (
            "11001001000", // 9  — )
            "11001000100", // 10 — *
            "11000100100", // 11 — +
            "10110011100", // 12 — ,
            "10011011100", // 13 — -
            "10011001110", // 14 — .
            "10111001100", // 15 — /
            "10011101100", // 16 — 0
            "10011100110", // 17 — 1
            "11001110010", // 18 — 2
            "11001011100", // 19 — 3
            "11001001110", // 20 — 4
            "11011100100", // 21 — 5
            "11001110100", // 22 — 6
            "11101101110", // 23 — 7
            "11101001100", // 24 — 8
            "11100101100", // 25 — 9
            "11100100110", // 26 — :
            "11101100100", // 27 — ;
            "11100110100", // 28 — <
            "11100110010", // 29 — =
            "11011011000", // 30 — >
            "11011000110", // 31 — ?
            "11000110110", // 32 — @
            "10100011000", // 33 — A
            "10001011000", // 34 — B
            "10001000110", // 35 — C
            "10110001000", // 36 — D
            "10001101000", // 37 — E
            "10001100010", // 38 — F
            "11010001000", // 39 — G
            "11000101000", // 40 — H
            "11000100010", // 41 — I
            "10110111000", // 42 — J
            "10110001110", // 43 — K
            "10001101110", // 44 — L
            "10111011000", // 45 — M
            "10111000110", // 46 — N
            "10001110110", // 47 — O
            "11101110110", // 48 — P
            "11010001110", // 49 — Q
            "11000101110", // 50 — R
            "11011101000", // 51 — S
            "11011100010", // 52 — T
            "11011101110", // 53 — U
            "11101011000", // 54 — V
            "11101000110", // 55 — W
            "11100010110", // 56 — X
            "11101101000", // 57 — Y
            "11101100010", // 58 — Z
            "11100011010", // 59 — [
            "11101111010", // 60 — \
            "11001000010", // 61 — ]
            "11110001010", // 62 — ^
            "10100110000", // 63 — _
            "10100001100", // 64 — `
            "10010110000", // 65 — a
            "10010000110", // 66 — b
            "10000101100", // 67 — c
            "10000100110", // 68 — d
            "10110010000", // 69 — e
            "10110000100", // 70 — f
            "10011010000", // 71 — g
            "10011000010", // 72 — h
            "10000110100", // 73 — i
            "10000110010", // 74 — j
            "11000010010", // 75 — k
            "11001010000", // 76 — l
            "11110111010", // 77 — m
            "11000010100", // 78 — n
            "10001111010", // 79 — o
            "10100111100", // 80 — p
            "10010111100", // 81 — q
            "10010011110", // 82 — r
            "10111100100", // 83 — s
            "10011110100", // 84 — t
            "10011110010", // 85 — u
            "11110100100", // 86 — v
            "11110010100", // 87 — w
            "11110010010", // 88 — x
            "11011011110", // 89 — y
            "11011110110", // 90 — z
            "11110110110", // 91 — {
            "10101111000", // 92 — |
            "10100011110", // 93 — }
            "10001011110", // 94 — ~
            "10111101000", // 95 — DEL (value 95 = symbol for DEL in Code B table)
            "10111100010", // 96
            "11110101000", // 97
            "11110100010", // 98
            "10111011110", // 99
            "10111101110", // 100
            "11101011110", // 101
            "11110101110", // 102 — FNC1
            "11010000100", // 103 — Start A
            "11010010000", // 104 — Start B
            "11010011100", // 105 — Start C
        };

        private const string StopPattern = "1100011101011";  // 13-module stop

        /// <summary>
        /// Encode a string (ASCII 32–126) as Code 128B and return the raw module
        /// bits: true = bar, false = space.
        /// </summary>
        public static bool[] Encode(string text)
        {
            // Validate: Code B supports ASCII 32–126
            foreach (char c in text)
                if (c < 32 || c > 126)
                    throw new ArgumentException($"Character '{c}' (0x{(int)c:X2}) is outside Code 128B range (ASCII 32-126).");

            var symbols = new List<int>();

            // Start Code B = symbol 104
            symbols.Add(104);

            int checksum = 104; // Start B symbol value
            int position = 1;

            foreach (char c in text)
            {
                // Code B: symbol value = ASCII value - 32
                int sym = c - 32;
                symbols.Add(sym);
                checksum += sym * position;
                position++;
            }

            // Check symbol
            symbols.Add(checksum % 103);

            // Build bit array
            var bits = new List<bool>();

            foreach (var sym in symbols)
            {
                var pattern = Patterns[sym];
                foreach (char bit in pattern)
                    bits.Add(bit == '1');
            }

            // Stop pattern (always bar-start, 13 modules)
            foreach (char bit in StopPattern)
                bits.Add(bit == '1');

            return bits.ToArray();
        }
    }
}
